class Meta(type):
    def __call__(cls, *args, **kwargs):
        print("Meta call")
        instance = super().__call__(*args, **kwargs)
        return instance

class Base(metaclass=Meta):
    def __new__(cls, x):
        print("Base new")
        return super().__new__(cls)
    def __init__(self, x):
        print("Base init")
        self.x = x

class Derived(Base):
    def __new__(cls, x):
        print("Derived new")
        return super().__new__(cls, x)
    def __init__(self, x):
        print("Derived init")
        super().__init__(x + 1)

def decorator(func):
    def wrapper(*args, **kwargs):
        print("Wrapper before")
        result = func(*args, **kwargs)
        print("Wrapper after")
        return result
    return wrapper

@decorator
def greet(name):
    print(f"Hello {name}")
    return name.upper()

def gen():
    x = yield 1
    y = yield x + 2
    yield y + 3

g = gen()
first = next(g)
second = g.send(10)
try:
    third = g.send(20)
except StopIteration:
    third = None

# ---------- final output ----------
print("Results:", Derived(5).x, greet("world"), first, second, third)


Which statements are TRUE?

a. The value printed as Derived(5).x is 6.
b. During the execution of print(...), the string "Meta call" appears exactly once in the output.
c. The call greet("world") returns the string "Hello world".
d. The final print line is Results: 6 WORLD 1 12 23.
e. The variable third ends up as None because of the StopIteration exception.
f. The output produced by the print statement will show "Wrapper before" before "Hello world" and "Wrapper after" after "Hello world".
g. If we remove super().__init__(x + 1) from Derived.__init__, then Derived(5).x will still be 6.
h. The generator gen() yields exactly three values before exhausting.
